有这样一个场景， 我们在e这个包下， 有一个err_code.go文件，在其中自定义了一个错误码结构体和一些错误码，内容如下:
package etype ErrCode struct &#123;	Code int	Msg  string&#125;var (	Success            = ErrCode&#123;Code: 10000, Msg: &quot;&quot;&#125;	UnknownErr         = ErrCode&#123;Code: 10001, Msg: &quot;未知错误&quot;&#125;	InvalidParams      = ErrCode&#123;Code: 10002, Msg: &quot;参数不合法&quot;&#125;)

现在我们想获取到所有这些预先定义的错误码的code，应该如何做呢？
可以借助go标准库中AST语法树的能力遍历所有变量，然后过滤得到我们想要的变量类型， 具体代码如下：
func Test_IntlDictMatchErrCodeEnum(t *testing.T) &#123;	fset := token.NewFileSet()    // 此处填写错误码所处包的相对路径	pkgs, err := parser.ParseDir(fset, &quot;../pkg/e&quot;, nil, parser.ParseComments)	if err != nil &#123;		log.Fatal(err)	&#125;	// 此处填写实际包的名字	pkg := pkgs[&quot;e&quot;] 	// 遍历文件	for _, file := range pkg.Files &#123;		// 遍历文件的声明		for _, decl := range file.Decls &#123;			// 检查声明是否是变量声明			if genDecl, ok := decl.(*ast.GenDecl); ok &amp;&amp; genDecl.Tok == token.VAR &#123;				// 遍历变量声明的规范				for _, spec := range genDecl.Specs &#123;					if valueSpec, ok := spec.(*ast.ValueSpec); ok &#123;						codeElt := valueSpec.Values[0]						if y, ok := codeElt.(*ast.CompositeLit); ok &#123;							if j, ok := y.Elts[0].(*ast.KeyValueExpr); ok &#123;								if l, ok := j.Value.(*ast.BasicLit); ok &#123;                                    // 此处能获取到错误码对应的Code                                    fmt.Printf(&quot;code:%s\n&quot;, l.Value)								&#125;							&#125;						&#125;					&#125;				&#125;			&#125;		&#125;	&#125;&#125;

常规使用java进行图片裁剪或压缩的时候， 比如使用ImageIO.read()读取图片信息的时候， 或者使用Thumb nails框架进行压缩时， 都会调用DataBufferByte类的下面这个方法：
public DataBufferByte(int size, int numBanks) &#123;        super(STABLE, TYPE_BYTE, size, numBanks);        bankdata = new byte[numBanks][];        for (int i= 0; i &lt; numBanks; i++) &#123;            // 构造数组            bankdata[i] = new byte[size];        &#125;        data = bankdata[0];&#125;

当图片像素很大时， size的值会很大， 此时构造这个数据就有可能会出现oom，比如当一张6.4M的图片， 宽高是5472*7296， size的值是114M。
基于此， 可以基于采样的方式进行， 不需要引用任何第三方库， 具体代码如下：
public static byte[] resize(byte[] srcFileData, int width, int height) &#123;    ImageInputStream input = null;    ImageReader reader = null;    try &#123;        input = ImageIO.createImageInputStream(new ByteArrayInputStream(srcFileData));        Iterator&lt;ImageReader&gt; readers = ImageIO.getImageReaders(input);        reader = readers.next();        reader.setInput(input);        //原始图像的长和宽        int srcWidth = reader.getWidth(0);        int srcHeight = reader.getHeight(0);        ImageReadParam param = reader.getDefaultReadParam();        int sampling = Math.min(srcWidth/width, srcHeight/height);        //采样压缩, 其中sampling的值表示每隔多少个像素点取一个像素        param.setSourceSubsampling(sampling, sampling, 0, 0);        // 裁剪        param.setSourceRegion(new Rectangle(0, 0, srcWidth, srcHeight));        BufferedImage bufferedImage = reader.read(0, param);        ByteArrayOutputStream outputStream = new ByteArrayOutputStream();        ImageIO.write(bufferedImage, &quot;jpg&quot;, outputStream);        return outputStream.toByteArray();    &#125; catch (IOException e) &#123;        e.printStackTrace();    &#125; finally &#123;        try &#123;            input.close();            if (reader != null)&#123;                reader.dispose();            &#125;        &#125; catch (IOException e) &#123;            e.printStackTrace();        &#125;            &#125;    return new byte[]&#123;&#125;;&#125;
